  const effectiveStrokeWidth = name === "whistle" ? Math.max(strokeWidth, 2.1) : strokeWidth;

  return (
    <svg
      className={`app-icon app-icon-${name} ${className}`.trim()}
      viewBox="0 0 24 24"
      width={size}
      height={size}
      fill="none"
      stroke="currentColor"
      strokeWidth={effectiveStrokeWidth}
      strokeLinecap="round"
      strokeLinejoin="round"
      aria-hidden="true"
      {...rest}
    >
      {renderIconPath(name)}
    </svg>
  );
